import React, { useEffect, useState } from 'react';
import axios from 'axios';
import TaskList from './TaskList';
import { useNavigate } from 'react-router-dom';
import MenuBar from './MenuBar';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [userRole, setUserRole] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const fetchUserRole = async () => {
      try {
        const token = localStorage.getItem('token');
        const cleanedToken = token?.replace(/^Bearer\s+/i, '');

        // Fetch user profile to get the role
        const response = await axios.get('http://localhost:3000/api/auth/profile', {
          headers: { Authorization: `Bearer ${cleanedToken}` },
        });

        setUserRole(response.data.role);
        localStorage.setItem('role', response.data.role); // ✅ Store role in localStorage
      } catch (error) {
        console.error('Error fetching user role:', error);
      }
    };

    const fetchTasks = async () => {
      try {
        const token = localStorage.getItem('token');
        const cleanedToken = token?.replace(/^Bearer\s+/i, '');

        const response = await axios.get('http://localhost:3000/api/tasks', {
          headers: { Authorization: `Bearer ${cleanedToken}` },
        });

        setTasks(response.data);
      } catch (error) {
        if (error.response && error.response.status === 401) {
          navigate('/');
        }
      }
    };

    fetchUserRole();
    fetchTasks();
  }, [navigate]);

  return (
    <div>
      <MenuBar />
      <h2>Dashboard</h2>

      {tasks.length === 0 ? (
        <div>
          <p>No tasks available. Please create a new task.</p>
          <button onClick={() => navigate('/add-task')}>Create New Task</button>
        </div>
      ) : (
        <TaskList tasks={tasks} />
      )}
    </div>
  );
};

export default Dashboard;
